const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];

const sumItemPremiums = (items: any[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0);

const groupByType = (items: any[]): Record<string, any[]> =>
  items.reduce((groups, item) => {
    (groups[item.type] ||= []).push(item);
    return groups;
  }, {} as Record<string, any[]>);

const calculateBasePremium = (items: any[]): number => {
  const groups = groupByType(items);
  let total = 0;
  for (const type in groups) {
    const group = groups[type];
    if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
      total += BLOCK_PRICE;
    } else {
      total += sumItemPremiums(group);
    }
  }
  return total;
};
